import React, { useState } from 'react';
import { EmptyState, Layout, Page } from '@shopify/polaris';
import { ResourcePicker, TitleBar } from '@shopify/app-bridge-react';
import { useMutation, useQuery } from '@apollo/react-hooks';
import gql from 'graphql-tag';
import store from 'store-js';
import ProductList from '../components/ProductList';
import { DiscountCodeBasicInput } from "shopify-admin-api-typings";

const DISCOUNT_CODE = gql`
  mutation discountCodeBasicCreate($basicCodeDiscount: DiscountCodeBasicInput!) {
  discountCodeBasicCreate(basicCodeDiscount: $basicCodeDiscount) {
    codeDiscountNode {
      id
    }
    userErrors {
      code
      extraInfo
      field
      message
    }
  }
 }
`;


const stuff = {
  "startsAt": "2021-03-05T19:34:35.948Z",
  "endsAt": null,
  "usageLimit": null,
  "appliesOncePerCustomer": false,
  "title": "WWFEDXGS9RVZ",
  "code": "WWFEDXGS9RVZ"
}

function Index() {
  const [addTodo, { data }] = useMutation<{ discountCodeBasicInputout: DiscountCodeBasicInput }>(DISCOUNT_CODE);
  return (
    <Page>
      <TitleBar
        primaryAction={{
          content: 'Select New Products',
          onAction: (e) => {
            addTodo(stuff);
          }
        }}
      />
    </Page>
  )

}

export default Index;
